"use client";

import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import NavbarSearch from "./NavbarSearch";
import {
  House,
  ClipboardList,
  Wallet,
  ShoppingCart,
  Shield,
  Settings,
  Globe,
  LogIn,
  LogOut,
  Bell,
  Trash2,
} from "lucide-react";
import { useSettings } from "@/lib/settings";

export default function Navbar() {
  const pathname = usePathname();
  const router = useRouter();
  const {
    lang,
    setLang,
    notifications,
    setNotifications,
    isLoggedIn,
    isAuthLoading,
    userName,
    userUsername,
    logout,
    clearAppData,
  } = useSettings();

  const hi = lang === "hi";
  const showSearch = !pathname.startsWith("/admin");

  const labels = {
    home: hi ? "\u0939\u094b\u092e" : "Home",
    myOrders: hi ? "\u092e\u0947\u0930\u0947 \u0911\u0930\u094d\u0921\u0930" : "My Orders",
    wallet: hi ? "\u0935\u0949\u0932\u0947\u091f" : "Wallet",
    cart: hi ? "\u0915\u093e\u0930\u094d\u091f" : "Cart",
    admin: "Admin",
    settings: hi ? "\u0938\u0947\u091f\u093f\u0902\u0917\u094d\u0938" : "Settings",
    language: hi ? "\u092d\u093e\u0937\u093e" : "Language",
    english: "English",
    hindi: "\u0939\u093f\u0902\u0926\u0940",
    login: hi ? "\u0932\u0949\u0917\u093f\u0928" : "Login",
    logout: hi ? "\u0932\u0949\u0917\u0906\u0909\u091f" : "Logout",
    notifications: hi ? "\u0928\u094b\u091f\u093f\u092b\u093f\u0915\u0947\u0936\u0928" : "Notifications",
    clearData: hi ? "\u090f\u092a \u0921\u0947\u091f\u093e \u0938\u093e\u092b \u0915\u0930\u0947\u0902" : "Clear app data",
    profile: hi ? "\u092a\u094d\u0930\u094b\u092b\u093e\u0907\u0932" : "Profile",
    fastDelivery: hi ? "\u092b\u093e\u0938\u094d\u091f \u0932\u094b\u0915\u0932 \u0921\u093f\u0932\u0940\u0935\u0930\u0940" : "Fast local delivery",
  };

  const navItems = [
    { href: "/", label: labels.home, icon: House },
    { href: "/my-orders", label: labels.myOrders, icon: ClipboardList },
    { href: "/my-orders#wallet", label: labels.wallet, icon: Wallet },
    { href: "/cart", label: labels.cart, icon: ShoppingCart },
    { href: "/admin", label: labels.admin, icon: Shield },
  ];

  return (
    <div className="border-b bg-white">
      <div className="mx-auto flex max-w-6xl items-center gap-4 px-4 py-3">
        <Link href="/" className="flex items-center gap-2">
          <div className="h-8 w-8 rounded bg-black" />
          <div className="leading-tight">
            <div className="font-semibold">BabaiBazaar</div>
            <div className="text-xs text-neutral-500">{labels.fastDelivery}</div>
          </div>
        </Link>

        <div className="flex-1">{showSearch ? <NavbarSearch /> : null}</div>

        <div className="flex items-center gap-2">
          <nav className="flex items-center gap-2 rounded-xl border bg-gray-50 p-1 text-sm">
            {navItems.map((item) => {
              const isActive = pathname === item.href || (item.href !== "/" && pathname.startsWith(item.href));
              const Icon = item.icon;

              return (
                <Link
                  key={item.href}
                  href={item.href}
                  className={`inline-flex items-center gap-2 rounded-lg px-3 py-2 font-medium transition ${
                    isActive ? "bg-black text-white shadow-sm" : "text-gray-700 hover:bg-white hover:text-black"
                  }`}
                >
                  <Icon className="h-4 w-4" />
                  <span>{item.label}</span>
                </Link>
              );
            })}
          </nav>

          <details className="relative">
            <summary className="list-none cursor-pointer rounded-xl border bg-gray-50 p-2 text-gray-700 hover:bg-white">
              <Settings className="h-5 w-5" />
            </summary>

            <div className="absolute right-0 z-50 mt-2 w-72 rounded-xl border bg-white p-3 shadow-xl">
              <div className="mb-2 text-sm font-semibold">{labels.settings}</div>

              <div className="mb-3 rounded-lg border p-2">
                <div className="mb-2 flex items-center gap-2 text-xs font-medium text-gray-600">
                  <Globe className="h-4 w-4" />
                  {labels.language}
                </div>
                <div className="grid grid-cols-2 gap-2">
                  <button
                    type="button"
                    onClick={() => setLang("en")}
                    className={`rounded-lg border px-2 py-1.5 text-xs font-medium ${
                      lang === "en" ? "bg-black text-white" : "bg-white"
                    }`}
                  >
                    {labels.english}
                  </button>
                  <button
                    type="button"
                    onClick={() => setLang("hi")}
                    className={`rounded-lg border px-2 py-1.5 text-xs font-medium ${
                      lang === "hi" ? "bg-black text-white" : "bg-white"
                    }`}
                  >
                    {labels.hindi}
                  </button>
                </div>
              </div>

              <div className="mb-3 rounded-lg border p-2">
                <div className="mb-1 text-xs font-medium text-gray-600">{labels.profile}</div>

                {isAuthLoading ? (
                  <div className="mb-2 text-xs text-gray-500">...</div>
                ) : isLoggedIn ? (
                  <div className="mb-2 text-xs text-gray-700">{userName ? `${userName} • ` : ""}@{userUsername}</div>
                ) : null}

                {!isLoggedIn ? (
                  <button
                    type="button"
                    className="inline-flex w-full items-center justify-center gap-2 rounded-lg border px-2 py-1.5 text-xs font-medium"
                    onClick={() => router.push("/login")}
                  >
                    <LogIn className="h-4 w-4" />
                    {labels.login}
                  </button>
                ) : (
                  <button
                    type="button"
                    className="inline-flex w-full items-center justify-center gap-2 rounded-lg border px-2 py-1.5 text-xs font-medium"
                    onClick={async () => {
                      await logout();
                      router.refresh();
                    }}
                  >
                    <LogOut className="h-4 w-4" />
                    {labels.logout}
                  </button>
                )}
              </div>

              <div className="mb-2 rounded-lg border p-2">
                <button
                  type="button"
                  onClick={() => setNotifications(!notifications)}
                  className="inline-flex w-full items-center justify-between rounded-lg border px-2 py-1.5 text-xs"
                >
                  <span className="inline-flex items-center gap-2">
                    <Bell className="h-4 w-4" />
                    {labels.notifications}
                  </span>
                  <span className={notifications ? "text-green-700" : "text-gray-500"}>
                    {notifications ? "ON" : "OFF"}
                  </span>
                </button>
              </div>

              <button
                type="button"
                onClick={() => {
                  clearAppData();
                  router.refresh();
                }}
                className="inline-flex w-full items-center justify-center gap-2 rounded-lg border border-red-200 px-2 py-1.5 text-xs font-medium text-red-700 hover:bg-red-50"
              >
                <Trash2 className="h-4 w-4" />
                {labels.clearData}
              </button>
            </div>
          </details>
        </div>
      </div>
    </div>
  );
}
